import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";import"./chunks/assets.Bet3gYyY.js";var i=JSON.parse(`{"title":"ACM Programming Competition","description":"Introduction to the ACM Programming Competition (ACM-XCPC) and participation guide, covering team recruitment, training schedules, competition rules, and more","frontmatter":{"lang":"en-US","title":"ACM Programming Competition","description":"Introduction to the ACM Programming Competition (ACM-XCPC) and participation guide, covering team recruitment, training schedules, competition rules, and more","llm_translated":true},"headers":[],"relativePath":"en/learn/extra/contest/ACM.md","filePath":"en/learn/extra/contest/ACM.md","lastUpdated":1784829332000}`),a={name:`en/learn/extra/contest/ACM.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/learn/extra/contest/ACM.md for this page in Markdown format</div><h1 id="acm-competition-introduction" tabindex="-1">ACM Competition Introduction <a class="header-anchor" href="#acm-competition-introduction" aria-label="Permalink to “ACM Competition Introduction”">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h2><p><strong>Organizer: Association for Computing Machinery (ACM)</strong></p><p>The ACM International Collegiate Programming Contest (abbreviated as <strong>ACM-ICPC</strong>) is one of the most influential university-level algorithm competitions worldwide. The competition is team-based, with each team consisting of three members, testing participants&#39; skills in algorithm design, programming ability, and teamwork.</p><p>The SCUT ACM Training Team organizes and selects outstanding students on campus to participate in various competitions, including:</p><ul><li><strong>ICPC (International Collegiate Programming Contest)</strong></li><li><strong>CCPC (China Collegiate Programming Contest)</strong></li><li><strong>GDCPC (Guangdong Collegiate Programming Contest)</strong></li><li><strong>Joint inter-university contests with SCUT&#39;s neighboring schools (GDUT, GZHU, SCNU, JNU, etc.)</strong></li><li><strong>Lanqiao Cup, corporate-sponsored competitions, etc.</strong></li></ul><hr><h2 id="acm-competition-rules-overview" tabindex="-1">ACM Competition Rules Overview <a class="header-anchor" href="#acm-competition-rules-overview" aria-label="Permalink to “ACM Competition Rules Overview”">​</a></h2><h3 id="competition-format" tabindex="-1">Competition Format <a class="header-anchor" href="#competition-format" aria-label="Permalink to “Competition Format”">​</a></h3><ul><li><strong>Three people per team</strong></li><li><strong>Only the team leader&#39;s computer can submit code</strong></li><li>The other two members can only read problems and discuss ideas</li><li><strong>Duration: 5 hours</strong></li><li><strong>Number of problems: 7 to 12</strong></li><li><strong>Printed reference materials are allowed</strong></li><li><strong>Common languages: C++, Java, Python (C++ recommended for speed)</strong></li><li><strong>Problem statements are entirely in English</strong></li></ul><p>Generally, ACM-related competition problems consist of the following sections:</p><ul><li><strong>Time Limit</strong></li><li><strong>Memory Limit</strong></li><li><strong>Description</strong></li><li><strong>Input</strong></li><li><strong>Output</strong></li><li><strong>Sample Input/Output</strong></li></ul><p>Submitted code can result in the following verdicts:</p><table tabindex="0"><thead><tr><th>Abbreviation</th><th>Full Name</th><th>Meaning</th></tr></thead><tbody><tr><td>AC</td><td>Accept</td><td>Accepted</td></tr><tr><td>WA</td><td>Wrong Answer</td><td>Wrong answer</td></tr><tr><td>CE</td><td>Compile Error</td><td>Compilation error</td></tr><tr><td>TLE</td><td>Time Limit Exceeded</td><td>Time limit exceeded</td></tr><tr><td>MLE</td><td>Memory Limit Exceeded</td><td>Memory limit exceeded</td></tr><tr><td>PE</td><td>Presentation Error</td><td>Format error</td></tr></tbody></table><blockquote><p>⚠️ Only <strong>AC</strong> means the problem is solved; all other verdicts indicate an issue with the code.</p></blockquote><h3 id="scoring-mechanism" tabindex="-1">Scoring Mechanism <a class="header-anchor" href="#scoring-mechanism" aria-label="Permalink to “Scoring Mechanism”">​</a></h3><ul><li><strong>Primary ranking: number of problems solved</strong> — the more, the higher the rank</li><li><strong>Secondary ranking: total time</strong> — total time = ∑(time of correct submission + penalty) <ul><li>Each incorrect submission (except CE) adds a 20-minute penalty</li><li>Penalty is only counted for problems that are eventually solved</li></ul></li><li><strong>Freeze mechanism</strong>: The scoreboard freezes 1 hour before the end, with final results revealed after the contest (may involve “scoreboard rolling”)</li></ul><h3 id="reward-mechanism" tabindex="-1">Reward Mechanism <a class="header-anchor" href="#reward-mechanism" aria-label="Permalink to “Reward Mechanism”">​</a></h3><ul><li>Balloons are awarded for solving problems</li><li>The first team to solve a problem receives a special balloon</li></ul><hr><h2 id="training-team-selection-and-training-plan" tabindex="-1">Training Team Selection and Training Plan <a class="header-anchor" href="#training-team-selection-and-training-plan" aria-label="Permalink to “Training Team Selection and Training Plan”">​</a></h2><h3 id="_1-recruitment-period" tabindex="-1">1. Recruitment Period <a class="header-anchor" href="#_1-recruitment-period" aria-label="Permalink to “1. Recruitment Period”">​</a></h3><ul><li><strong>Only one recruitment opportunity per year</strong>, typically at the beginning of the academic year.</li><li>Missing it means waiting until next year — start preparing early!</li></ul><h3 id="_2-training-schedule" tabindex="-1">2. Training Schedule <a class="header-anchor" href="#_2-training-schedule" aria-label="Permalink to “2. Training Schedule”">​</a></h3><ul><li><strong>Regular training</strong>: 5-hour sessions every weekend (simulating actual contest duration)</li><li><strong>Winter and summer break training</strong>: <ul><li><strong>Winter break</strong>: Senior students teach basic algorithm knowledge</li><li><strong>Summer break</strong>: Participate in national joint training camps</li></ul></li></ul><h3 id="_3-competition-participation" tabindex="-1">3. Competition Participation <a class="header-anchor" href="#_3-competition-participation" aria-label="Permalink to “3. Competition Participation”">​</a></h3><ul><li>Main target competitions are <strong>ICPC</strong> and <strong>CCPC</strong></li><li>Qualify for regional rounds through online contests in the first semester</li><li>Outstanding performers can advance to <strong>EC-Final</strong> or <strong>CCPC Final</strong></li><li>Other recommended competitions include Lanqiao Cup and corporate-sponsored contests — opportunities for prize money and comprehensive evaluation bonus points</li></ul><hr><h2 id="registration-and-timeline" tabindex="-1">Registration and Timeline <a class="header-anchor" href="#registration-and-timeline" aria-label="Permalink to “Registration and Timeline”">​</a></h2><h3 id="registration-channels" tabindex="-1">Registration Channels <a class="header-anchor" href="#registration-channels" aria-label="Permalink to “Registration Channels”">​</a></h3><ul><li><strong>On-campus selection</strong>: Join the training team through the SCUT ACM campus competition</li></ul><h3 id="competition-schedule" tabindex="-1">Competition Schedule <a class="header-anchor" href="#competition-schedule" aria-label="Permalink to “Competition Schedule”">​</a></h3><table tabindex="0"><thead><tr><th>Competition</th><th>Timing</th></tr></thead><tbody><tr><td>ICPC / CCPC</td><td>Usually held in the fall semester</td></tr><tr><td>GDCPC</td><td>Provincial competition, usually in spring semester</td></tr><tr><td>Lanqiao Cup</td><td>Preliminary in spring, finals in summer</td></tr></tbody></table><hr><h2 id="advantages-of-joining-the-training-team" tabindex="-1">Advantages of Joining the Training Team <a class="header-anchor" href="#advantages-of-joining-the-training-team" aria-label="Permalink to “Advantages of Joining the Training Team”">​</a></h2><ul><li><strong>Rich learning resources</strong>: One-on-one Q&amp;A with experienced seniors, covering academics and daily life</li><li><strong>Networking opportunities</strong>: Meet like-minded teammates, beneficial for future projects or job hunting</li><li><strong>Practical experience</strong>: Winter and summer break training counts as social practice</li><li><strong>Comprehensive evaluation bonus</strong>: Awards earn intellectual development points</li><li><strong>Graduate recommendation edge</strong>: Strong competition performance means better coding skills in graduate school interviews, especially helpful for computer-related majors. <em>(Note: Specific policies vary by school)</em></li><li><strong>Career advantages</strong>: Winning corporate-sponsored competitions can lead directly to internships or job offers at well-known companies. Solid algorithm foundations and hands-on experience give you an edge in technical interviews. Plus, employed seniors can provide internal referrals, significantly improving job search success.</li><li><strong>Research boost</strong>: Lab professors prefer students with competition backgrounds</li></ul><hr><h2 id="getting-started-for-newcomers" tabindex="-1">Getting Started for Newcomers <a class="header-anchor" href="#getting-started-for-newcomers" aria-label="Permalink to “Getting Started for Newcomers”">​</a></h2><h3 id="choosing-a-programming-language" tabindex="-1">Choosing a Programming Language <a class="header-anchor" href="#choosing-a-programming-language" aria-label="Permalink to “Choosing a Programming Language”">​</a></h3><ul><li><strong>C++ is recommended</strong>: Fast, well-suited for algorithm competitions</li><li>Python / Java, due to interpreted language characteristics, are prone to timeouts and only suitable for a few big-number problems</li></ul><h3 id="development-environment-suggestions" tabindex="-1">Development Environment Suggestions <a class="header-anchor" href="#development-environment-suggestions" aria-label="Permalink to “Development Environment Suggestions”">​</a></h3><ul><li><strong>Windows</strong>: <ul><li>Beginners: Use <strong>Code::Blocks</strong> or <strong>Dev-C++</strong></li><li>Advanced users: Use <strong>VSCode + MinGW / WSL + GNU G++</strong></li></ul></li><li><strong>Linux users</strong>: Configure as you like</li><li><strong>Mac users</strong>: Try VSCode + Clang compiler</li></ul><h3 id="recommended-learning-resources" tabindex="-1">Recommended Learning Resources <a class="header-anchor" href="#recommended-learning-resources" aria-label="Permalink to “Recommended Learning Resources”">​</a></h3><ul><li><strong>C++ Quick Start</strong>: <a href="https://www.runoob.com/cplusplus/cpp-tutorial.html" target="_blank" rel="noreferrer">Runoob - C++ Tutorial</a></li><li><strong>OI Wiki</strong>: <a href="https://oi-wiki.org/" target="_blank" rel="noreferrer">OI-Wiki</a></li><li><strong>Practice Platforms</strong>: <ul><li><a href="https://www.luogu.com.cn/" target="_blank" rel="noreferrer">Luogu</a></li><li><a href="https://leetcode.cn/problemset/all/" target="_blank" rel="noreferrer">LeetCode</a></li><li><a href="https://codeforces.com/" target="_blank" rel="noreferrer">Codeforces</a></li></ul></li><li><strong>Algorithm Templates</strong>: <ul><li><a href="https://www.cnblogs.com/WIDA/p/17633758.html" target="_blank" rel="noreferrer">jiangly Algorithm Template Collection - hh2048 - cnblogs</a></li></ul></li></ul><h3 id="beginner-learning-path" tabindex="-1">Beginner Learning Path <a class="header-anchor" href="#beginner-learning-path" aria-label="Permalink to “Beginner Learning Path”">​</a></h3><ol><li>Learn basic syntax (recommended: “Programming Contests: From Entry to Mastery”)</li><li>Master fundamental algorithms: <ul><li>Binary search</li><li>Greedy algorithms</li><li>Dynamic programming (DP)</li><li>Search (DFS/BFS)</li></ul></li><li>Improve English reading comprehension (all problem statements are in English)</li></ol><hr><h2 id="preparation-strategy-for-new-students" tabindex="-1">Preparation Strategy (For New Students) <a class="header-anchor" href="#preparation-strategy-for-new-students" aria-label="Permalink to “Preparation Strategy (For New Students)”">​</a></h2><h3 id="quick-start-roadmap" tabindex="-1">Quick Start Roadmap <a class="header-anchor" href="#quick-start-roadmap" aria-label="Permalink to “Quick Start Roadmap”">​</a></h3><ol><li><strong>Master C++ basics</strong>: <ul><li>Data types, loops, function definitions, arrays, and string operations</li></ul></li><li><strong>Get familiar with the STL</strong>: <ul><li>Common containers like <code>vector</code>, <code>map</code>, <code>set</code>, <code>priority_queue</code></li></ul></li><li><strong>Practice to gain experience</strong>: <ul><li>Start with easy problems, gradually move to medium difficulty</li></ul></li><li><strong>Simulate real contests</strong>: <ul><li>Participate in a 5-hour mock contest weekly to get used to the rhythm</li></ul></li></ol><h3 id="recommended-books" tabindex="-1">Recommended Books <a class="header-anchor" href="#recommended-books" aria-label="Permalink to “Recommended Books”">​</a></h3><ul><li>“Programming Contests: From Entry to Mastery” (Published by Luogu)</li><li>“Introduction to Algorithm Contests” (by Liu Rujia) <img src="/assets/%E6%B7%B1%E5%85%A5%E6%B5%85%E5%87%BA%E7%A8%8B%E5%BA%8F%E8%AE%BE%E8%AE%A1%E7%AB%9E%E8%B5%9B.CMB8JIdi.jpg" alt="Programming Contests: From Entry to Mastery"></li></ul><p><img src="/assets/%E7%AE%97%E6%B3%95%E7%AB%9E%E8%B5%9B%E5%85%A5%E9%97%A8%E7%BB%8F%E5%85%B8.CgPwATiq.jpg" alt="Introduction to Algorithm Contests"></p><h3 id="areas-for-improvement" tabindex="-1">Areas for Improvement <a class="header-anchor" href="#areas-for-improvement" aria-label="Permalink to “Areas for Improvement”">​</a></h3><ul><li><strong>English problem reading skills</strong>: Practice with original problem statements</li><li><strong>Debugging skills</strong>: Learn to use debugging tools</li><li><strong>Time management</strong>: Allocate problem-solving time wisely to avoid getting stuck</li></ul><hr><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to “Conclusion”">​</a></h2><p>Joining the ACM Training Team is not only an excellent opportunity to sharpen your programming skills and logical thinking, but also a significant springboard to higher academic platforms and quality career opportunities. As long as you are willing to invest time and effort and have the courage to challenge yourself, you have the chance to stand out and become a member of the SCUT ACM team!</p><p><strong>2025 SCUT ACM Training Team Recruitment QQ Group</strong>: 557553053</p>`,60)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};